//方法一: 调用Class类中的forName静态方法Class clazz = null;try &#123;    //fullClassPath为类的路径全称    clazz = Class.forName(&quot;java.util.HashMap&quot;);&#125; catch (ClassNotFoundException e) &#123;    e.printStackTrace();&#125;

//方法二: 调用HashMap类的class属性Class clazz = HashMap.class;

//方法三: 调用HashMap对象的getClass方法Map&lt;Integer, String&gt; map = new HashMap&lt;&gt;();Class clazz = map.getClass();

查看HashMap类的属性：
//查看全部属性Field[] fields = clazz.getDeclaredFields();//getDeclaredFields方法获取所有属性//getFields方法仅仅获取public修饰的属性//fields = clazz.getFields();for (Field field : fields) &#123;    //System.out.println(field.toString());&#125;//获取特定属性try &#123;    Field field = clazz.getDeclaredField(&quot;serialVersionUID&quot;);    //System.out.println(field.toString());&#125; catch (NoSuchFieldException e) &#123;    e.printStackTrace();&#125;

查看HashMap的构造信息：
//查看全部构造信息Constructor[] constructors = clazz.getDeclaredConstructors();//constructors = clazz.getConstructors();for (Constructor constructor : constructors) &#123;    //System.out.println(constructor.toString());&#125;//获取特定构造函数Constructor constructor = null;try &#123;    //constructor = clazz.getDeclaredConstructor(int.class, float.class);    constructor = clazz.getConstructor(int.class, float.class);    //System.out.println(constructor.toString());&#125; catch (NoSuchMethodException e) &#123;    e.printStackTrace();&#125;

查看HashMap方法：
//查看所有方法Method[] methods = clazz.getDeclaredMethods();//methods = clazz.getMethods();for (Method method : methods) &#123;    //System.out.println(method.toString());&#125;//获取特定方法Method method = null;try &#123;    //method = clazz.getDeclaredMethod(&quot;get&quot;, Object.class);    method = clazz.getMethod(&quot;get&quot;, Object.class);    //System.out.println(method.toString());&#125; catch (NoSuchMethodException e) &#123;    e.printStackTrace();&#125;

创建HashMap对象：
//方法一: 使用Class对象的newInstance方法HashMap&lt;Integer, String&gt; hashMap = null;try &#123;    hashMap = (HashMap&lt;Integer, String&gt;)clazz.newInstance();&#125; catch (InstantiationException | IllegalAccessException e) &#123;    e.printStackTrace();&#125;

方法二: 根据构造方法创建对象HashMap&lt;Integer, String&gt; hashMap = null;try &#123;    hashMap = (HashMap&lt;Integer, String&gt;)constructor.newInstance(16, 0.75f);    hashMap.put(1, &quot;hello&quot;);&#125; catch (InstantiationException | IllegalAccessException | InvocationTargetException e) &#123;    e.printStackTrace();&#125;

动态调用方法：
try &#123;    //相当于String str = hashMap.get(1);    String str = (String) method.invoke(hashMap, 1);    //System.out.println(str);&#125; catch (IllegalAccessException | InvocationTargetException e) &#123;    e.printStackTrace();&#125;

自定义注解接口：
package com.ccying.java.annotation;import java.lang.annotation.*;/** * @author ccying * @date 2018/11/14 *///注解修饰对象范围为域@Target(ElementType.FIELD)//在运行时有效，即在运行时被保留@Retention(RetentionPolicy.RUNTIME)//可以被javadoc类工具文档化@Documentedpublic @interface Valid &#123;    public int min() default 0;    public int max() default 0;    public boolean combination() default true;    public String description() default &quot;&quot;;&#125;

自定义异常：
package com.ccying.java.annotation;/** * @author ccying * @date 2018/11/16 */public class IllegalPasswordException extends Exception &#123;    public IllegalPasswordException (String message) &#123;        super(message);    &#125;&#125;

使用注解：
package com.ccying.java.annotation;import java.io.Serializable;/** * @author ccying * @date 2018/11/14 */public class Auth implements Serializable &#123;    /**     * 账号     */    private String account;    /**     * 密码     * */    @Valid(min = 6, max = 18, description = &quot;密码长度在6-18位数中间，且需要数字和字母组合&quot;)    private String password;    public Auth(String account, String password) &#123;        this.account = account;        this.password = password;    &#125;    public String getAccount() &#123;        return account;    &#125;    public void setAccount(String account) &#123;        this.account = account;    &#125;    public String getPassword() &#123;        return password;    &#125;    public void setPassword(String password) &#123;        this.password = password;    &#125;&#125;

注解处理器：
package com.ccying.java.annotation;import java.lang.reflect.Field;/** * @author ccying * @date 2018/11/14 */public class AuthValidHandler &#123;    /**     * 校验密码     * */    public static void password(Object object) throws IllegalPasswordException &#123;        //反射获取object password属性信息        Field field = null;        try &#123;            field = object.getClass().getDeclaredField(&quot;password&quot;);        &#125; catch (NoSuchFieldException e) &#123;            e.printStackTrace();        &#125;        if (field.isAnnotationPresent(Valid.class)) &#123;            //获取注解信息            Valid valid = field.getAnnotation(Valid.class);            String password = null;            try &#123;                //设值属性可访问                field.setAccessible(true);                //获取密码值                password = (String) field.get(object);            &#125; catch (IllegalAccessException e) &#123;                e.printStackTrace();            &#125;            if (password != null) &#123;                if (password.length() &lt; valid.min() || password.length() &gt; valid.max()) &#123;                    throw new IllegalPasswordException(&quot;密码长度要在&quot; + valid.min() + &quot;到&quot; + valid.max() + &quot;之间&quot;);                &#125;                boolean isDigit = false;                boolean isLetter = false;                boolean isCombination = false;                for (int i = 0; i &lt; password.length(); i++) &#123;                    char ch = (char) password.indexOf(i);                    if (Character.isDigit(ch)) &#123;                        isDigit = true;                    &#125; else if (Character.isLetter(ch)) &#123;                        isLetter = true;                    &#125;                    if (isDigit &amp;&amp; isLetter) &#123;                        isCombination = true;                        break;                    &#125;                &#125;                if (valid.combination() &amp;&amp; !isCombination) &#123;                    throw new IllegalPasswordException(&quot;密码需要数字和字母结合&quot;);                &#125;            &#125;        &#125;    &#125;&#125;

